    [FormControlEventHandler(formControlStr(DirPartyTable, DirPartyTable_UBSProcCategoryName), FormControlEventType::Modified)]
    public static void DirPartyTable_UBSProcCategoryName_OnModified(FormControl sender, FormControlEventArgs e)
    {
        FormStringControl   callerButton        = sender as FormStringControl;
        FormRun             form                = callerButton.formRun();
        FormDataSource      dirPartyTable_ds    = form.dataSource(formDataSourceStr(DirPartyTable, DirPartyTable)) as FormDataSource;
        DirPartyTable       dirPartyTable       = dirPartyTable_ds.cursor();

        dirPartyTable.UBSReferencing = UBSSupplierReferencing::findMinByProcCategory(dirPartyTable.UBSProcCategoryName).UBSReferencing;
    }

    /// <summary>
    /// Override UBSProcCategoryName lookup
    /// </summary>
    /// <param name="sender">FormControl</param>
    /// <param name="e">FormControlEventArgs</param>
    [FormControlEventHandler(formControlStr(DirPartyTable, DirPartyTable_UBSProcCategoryName), FormControlEventType::Lookup)]
    public static void DirPartyTable_UBSProcCategoryName_OnLookup(FormControl sender, FormControlEventArgs e)
    {
        str procCategoryLvl = int2Str(UBSVendParametersCC::find().UBSProcCategoryLvl);
        FormControlCancelableSuperEventArgs event = e as FormControlCancelableSuperEventArgs;

        SysTableLookup sysTableLookup = SysTableLookup::newParameters(tableNum(EcoResCategory),sender);
        sysTableLookup.addLookupField(fieldNum(EcoResCategory, Name));

        Query                query  = new Query();
        QueryBuildDataSource qds    = query.addDataSource(tableNum(EcoResCategory));
        QueryBuildRange      qr     = qds.addRange(fieldNum(EcoResCategory,Level));
        qr.value(procCategoryLvl);
        QueryBuildRange      qr2    = qds.addRange(fieldNum(EcoResCategory,IsActive));
        qr2.value('1');
        sysTableLookup.parmQuery(query);
        sysTableLookup.performFormLookup();
        event.CancelSuperCall();
    }

    /// <summary>
    /// Override UBSReferencing lookup
    /// </summary>
    /// <param name="sender">FormControl</param>
    /// <param name="e">FormControlEventArgs</param>
    [FormControlEventHandler(formControlStr(DirPartyTable, DirPartyTable_UBSReferencing), FormControlEventType::Lookup)]
    public static void DirPartyTable_UBSReferencing_OnLookup(FormControl sender, FormControlEventArgs e)
    {
        FormControlCancelableSuperEventArgs event = e as FormControlCancelableSuperEventArgs;

        SysTableLookup sysTableLookup = SysTableLookup::newParameters(tableNum(UBSSupplierReferencing),sender);
        sysTableLookup.addLookupField(fieldNum(UBSSupplierReferencing, UBSReferencing));

        Query                query   = new Query();
        QueryBuildDataSource qbds    = query.addDataSource(tableNum(UBSSupplierReferencing));
        qbds.addSortField(fieldNum(UBSSupplierReferencing,UBSReferencing));
        qbds.orderMode(ordermode::GroupBy);
        sysTableLookup.parmUseLookupValue(false);
        sysTableLookup.parmQuery(query);
        sysTableLookup.performFormLookup();
        event.CancelSuperCall();
    }
